CREATE TABLE IF NOT EXISTS collections(id TEXT PRIMARY KEY NOT NULL,name TEXT NOT NULL UNIQUE,description TEXT,created_at TEXT NOT NULL,updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS item_collections(item_id TEXT NOT NULL,collection_id TEXT NOT NULL,PRIMARY KEY(item_id,collection_id),FOREIGN KEY(item_id) REFERENCES items(id) ON DELETE CASCADE,FOREIGN KEY(collection_id) REFERENCES collections(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS tags(id TEXT PRIMARY KEY NOT NULL,name TEXT NOT NULL UNIQUE,color TEXT,created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS item_tags(item_id TEXT NOT NULL,tag_id TEXT NOT NULL,PRIMARY KEY(item_id,tag_id),FOREIGN KEY(item_id) REFERENCES items(id) ON DELETE CASCADE,FOREIGN KEY(tag_id) REFERENCES tags(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS activity_log(id TEXT PRIMARY KEY NOT NULL,item_id TEXT,event_type TEXT NOT NULL,payload_json TEXT NOT NULL,created_at TEXT NOT NULL,FOREIGN KEY(item_id) REFERENCES items(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS saved_searches(id TEXT PRIMARY KEY NOT NULL,name TEXT NOT NULL,query_json TEXT NOT NULL,created_at TEXT NOT NULL,updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS attachments(id TEXT PRIMARY KEY NOT NULL,item_id TEXT NOT NULL,name TEXT NOT NULL,path TEXT NOT NULL,mime_type TEXT,byte_size INTEGER NOT NULL,created_at TEXT NOT NULL,FOREIGN KEY(item_id) REFERENCES items(id) ON DELETE CASCADE);
